CREATE PROCEDURE AddEmployee(IN name VARCHAR(100), IN salary DECIMAL, IN deptId INT)
BEGIN
    INSERT INTO Employees(EmployeeName, Salary, DepartmentID, HireDate) VALUES (name, salary, deptId, date('now'));
END;

CREATE PROCEDURE TransferFunds(IN fromAcc INT, IN toAcc INT, IN amount DECIMAL)
BEGIN
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        ROLLBACK;
    END;

    START TRANSACTION;
    UPDATE Accounts SET Balance = Balance - amount WHERE AccountID = fromAcc;
    UPDATE Accounts SET Balance = Balance + amount WHERE AccountID = toAcc;
    COMMIT;
END;

